#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

int t,n,p[N];

int dfs(int x,int l1,int l2){
    if(x>n)
        return 0;
    return max(dfs(x+1,max(l1,p[x]),l2)+(p[x]>l1),dfs(x+1,l1,min(l2,p[x]))+(p[x]<l2));
}

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
            scanf("%d",&p[i]);
        printf("%d\n",dfs(1,0,n+1));
    }
    return 0;
}
